// Lattice Squish Ball — an OPEN gyroid-mesh sphere ("Fidget Morf" look).
// A sphere whose entire body is an open woven gyroid lattice: slender walls
// with big visible pores you can see straight through, in one vibrant color.
const { Manifold, CrossSection, sdf } = api;

const p = api.params({
  radius:   { type: 'number', default: 18, min: 10, max: 30, step: 1, unit: 'mm',
              label: 'Ball radius', help: 'Overall sphere radius.' },
  cellSize: { type: 'number', default: 11, min: 5, max: 16, step: 0.5,
              label: 'Lattice cell', help: 'Gyroid period in world units — bigger = fewer, larger cells.' },
  wall:     { type: 'number', default: 0.5, min: 0.2, max: 1.0, step: 0.05,
              label: 'Wall density', help: 'Gyroid field threshold: ~0.5 = open lattice; toward 1.0 the pores fill in solid.' },
  color:    { type: 'color',  default: '#7c5cff', label: 'Color' },
});

// HOW gyroid(cellSize, thickness) ACTUALLY WORKS (this bit the earlier drafts):
// the node is `(|F(k·p)| - thickness)/k`, so the surface is where |F| = thickness.
// The gyroid field F only ranges ~[-1.5, 1.5], so `thickness` is a FIELD
// THRESHOLD, not a millimetre wall width — values ≥1.1 select {|F| < 1.1}, which
// is nearly all of space, so the lattice renders as a solid blob. The working
// docs examples use gyroid(5, 0.5). Keep `wall` ≈ 0.4–0.7 for an open mesh whose
// two channels ({F > wall} and {F < -wall}) stay as see-through voids.
const lattice = sdf.gyroid(p.cellSize, p.wall);

// The ball domain. Intersecting with the finite sphere both clips the infinite
// lattice to a ball AND hands `.build()` finite bounds to mesh against.
const ball = sdf.sphere(p.radius);
const squishBall = lattice.intersect(ball);

// edgeLength is tied to the CELL (not the threshold) so the woven walls get a
// few triangles across without an enormous mesh: ~cellSize/16 is a good balance.
const mesh = squishBall.build({ edgeLength: Math.max(0.4, p.cellSize / 16) });

// One vibrant color. An open lattice clipped to a sphere naturally meshes as
// several disconnected shells at the silhouette — that's expected, not failure.
return api.label(mesh, 'lattice', { color: p.color });

